mapper.select:
SELECT *
FROM quality_inspection

    inspection_type = #{type}
    AND is_deleted = 0

        AND inspection_no LIKE CONCAT('%', #{inspectionNo}, '%')


        AND batch_no LIKE CONCAT('%', #{batchNo}, '%')


        AND roll_code LIKE CONCAT('%', #{rollCode}, '%')


        AND overall_result = #{result}


        AND inspection_time >= #{startDate}


        AND inspection_time <= #{endDate}


ORDER BY inspection_time DESC, id DESC
